			inactive_border = "rgba(595959aa)",
		},

		layout = "dwindle",
	},
	animations = { enabled = true },
	decoration = {
		rounding = 6,
		rounding_power = 2,
		-- Change transparency of focused and unfocused windows
		active_opacity = 1.0,
		inactive_opacity = 0.9,
		shadow = {
			enabled = false,
			range = 4,
			render_power = 3,
			color = "rgba(1a1a1aee)",
		},
		-- https://wiki.hyprland.org/Configuring/Variables/#blur
		blur = {
			enabled = false, -- Improving battery life
			size = 5,
			passes = 1,
